    #{refDeptCode}, #{refDeptName},
    #{refGradeCode}, #{refGradeName}
)

mapper.select:
SELECT fileId, docId, oriFilename, saveFilename, fileSize
FROM approvalFile
WHERE fileId = #{fileId}

mapper.update:
UPDATE approvalDoc
SET docStatus = 'CANCELED'
WHERE docId = #{docId}
  AND writerEmpId = #{empId}
  AND docStatus = 'PENDING'
  AND NOT EXISTS (
      SELECT 1 FROM approvalLine
      WHERE docId = #{docId}
        AND lineStatusCode != 'WAIT'
  )

UPDATE approvalLine
SET lineStatusCode = 'CANCELED'
WHERE docId = #{docId}

UPDATE approvalLine
SET lineStatusCode = 'APPROVED',
    apprDate = SYSDATE,
    apprComment = #{comment, jdbcType=VARCHAR}
WHERE docId = #{docId}
  AND apprEmpId = #{empId}
  AND (
      (lineStatusCode = 'WAIT' AND stepOrder = (
          SELECT MIN(stepOrder) FROM approvalLine
          WHERE docId = #{docId} AND lineStatusCode = 'WAIT'
      ))
      OR lineStatusCode = 'HOLD'
  )

UPDATE approvalDoc
SET docStatus = 'APPROVED', completeDate = SYSDATE
WHERE docId = #{docId}

UPDATE approvalLine
SET lineStatusCode = 'REJECTED',
    apprDate = SYSDATE,
    apprComment = #{comment, jdbcType=VARCHAR}
WHERE docId = #{docId}
  AND apprEmpId = #{empId}
  AND (
      (lineStatusCode = 'WAIT' AND stepOrder = (
          SELECT MIN(stepOrder) FROM approvalLine
          WHERE docId = #{docId} AND lineStatusCode = 'WAIT'
      ))
      OR lineStatusCode = 'HOLD'
  )

UPDATE approvalDoc
SET docStatus = 'REJECTED'
WHERE docId = #{docId}

UPDATE approvalLine
SET lineStatusCode = 'HOLD',
    apprDate = SYSDATE,
    apprComment = #{comment, jdbcType=VARCHAR}
WHERE docId = #{docId}
  AND apprEmpId = #{empId}
  AND lineStatusCode = 'WAIT'
  AND stepOrder = (
      SELECT MIN(stepOrder) FROM approvalLine
      WHERE docId = #{docId} AND lineStatusCode = 'WAIT'
  )

UPDATE approvalDoc
SET docStatus = 'ON_HOLD'
WHERE docId = #{docId}

UPDATE approvalReference
SET refComment = #{comment, jdbcType=VARCHAR},
    refCommentDate = SYSDATE
WHERE docId = #{docId}
  AND refEmpId = #{empId}
